import javax.jws.WebService;
import javax.jws.WebMethod;
import javax.jws.WebParam;
import javax.jws.soap.SOAPBinding;
import javax.jws.soap.SOAPBinding.Style;
import java.util.HashMap;
import java.util.Map;

@WebService(name = "EmployeeManagementService", targetNamespace = "http://hr.system.employee/")
@SOAPBinding(style = Style.DOCUMENT)
public class EmployeeManagementServiceImpl {
    
    private Map<String, Employee> employeeDatabase = new HashMap<>();
    
    public EmployeeManagementServiceImpl() {
        // Initialize with sample data
        employeeDatabase.put("EMP001", new Employee("EMP001", "John Doe", 50000.0, "Developer"));
        employeeDatabase.put("EMP002", new Employee("EMP002", "Jane Smith", 60000.0, "Manager"));
    }
    
    @WebMethod(operationName = "updateSalary")
    public UpdateResult updateSalary(@WebParam(name = "employeeId") String employeeId,
                                   @WebParam(name = "newSalary") double newSalary) {
        try {
            Employee employee = employeeDatabase.get(employeeId);
            if (employee != null) {
                double oldSalary = employee.getSalary();
                employee.setSalary(newSalary);
                return new UpdateResult(true, "Salary updated successfully from " + oldSalary + " to " + newSalary);
            } else {
                return new UpdateResult(false, "Employee not found with ID: " + employeeId);
            }
        } catch (Exception e) {
            return new UpdateResult(false, "Error updating salary: " + e.getMessage());
        }
    }
    
    @WebMethod(operationName = "performPerformanceReview")
    public ReviewResult performPerformanceReview(@WebParam(name = "employeeId") String employeeId,
                                               @WebParam(name = "reviewRating") String reviewRating,
                                               @WebParam(name = "comments") String comments) {
        try {
            Employee employee = employeeDatabase.get(employeeId);
            if (employee != null) {
                employee.setLastReviewRating(reviewRating);
                employee.setReviewComments(comments);
                return new ReviewResult(true, "Performance review completed successfully for " + employee.getName());
            } else {
                return new ReviewResult(false, "Employee not found with ID: " + employeeId);
            }
        } catch (Exception e) {
            return new ReviewResult(false, "Error performing review: " + e.getMessage());
        }
    }
    
    @WebMethod(operationName = "terminateEmployee")
    public TerminationResult terminateEmployee(@WebParam(name = "employeeId") String employeeId,
                                             @WebParam(name = "terminationReason") String terminationReason) {
        try {
            Employee employee = employeeDatabase.get(employeeId);
            if (employee != null) {
                employeeDatabase.remove(employeeId);
                return new TerminationResult(true, "Employee " + employee.getName() + " terminated successfully. Reason: " + terminationReason);
            } else {
                return new TerminationResult(false, "Employee not found with ID: " + employeeId);
            }
        } catch (Exception e) {
            return new TerminationResult(false, "Error terminating employee: " + e.getMessage());
        }
    }
    
    @WebMethod(operationName = "getEmployeeDetails")
    public Employee getEmployeeDetails(@WebParam(name = "employeeId") String employeeId) {
        return employeeDatabase.get(employeeId);
    }
    
    @WebMethod(operationName = "getAllEmployees")
    public Employee[] getAllEmployees() {
        return employeeDatabase.values().toArray(new Employee[0]);
    }
    
    public static void main(String[] args) {
        javax.xml.ws.Endpoint.publish("http://localhost:8080/hr/employee", new EmployeeManagementServiceImpl());
        System.out.println("Employee Management Service is running at http://localhost:8080/hr/employee");
    }
}

